using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    vector<vector<pair<long long, long long>>> adj(n);
    vector<vector<pair<long long, long long>>> reverse_adj(n);

    for (const auto& edge : edges) {
        long long u = edge[0], v = edge[1], w = edge[2];
        adj[u].emplace_back(v, w);
        reverse_adj[v].emplace_back(u, w);
    }

    priority_queue<pair<long long, pair<long long, bool>>, 
                   vector<pair<long long, pair<long long, bool>>>, 
                   greater<pair<long long, pair<long long, bool>>>> pq;

    vector<vector<long long>> dist(n, vector<long long>(2, LLONG_MAX));
    dist[0][0] = 0;
    pq.push({0, {0, 0}});

    while (!pq.empty()) {
        auto current = pq.top();
        pq.pop();
        long long current_dist = current.first;
        long long u = current.second.first;
        bool used = current.second.second;

        if (current_dist > dist[u][used]) {
            continue;
        }

        for (const auto& edge : adj[u]) {
            long long v = edge.first;
            long long w = edge.second;
            if (dist[v][used] > current_dist + w) {
                dist[v][used] = current_dist + w;
                pq.push({dist[v][used], {v, used}});
            }
        }

        if (!used) {
            for (const auto& edge : reverse_adj[u]) {
                long long v = edge.first;
                long long w = edge.second;
                if (dist[v][true] > current_dist + 2 * w) {
                    dist[v][true] = current_dist + 2 * w;
                    pq.push({dist[v][true], {v, true}});
                }
            }
        }
    }

    long long result = min(dist[n-1][0], dist[n-1][1]);
    return result == LLONG_MAX ? -1 : result;
}

